  ('aboriginal-a5729396-moex-00383', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '甲向乙購買二手車一輛，乙尚未交付前，該車即滅失。依民法規定，下列敘述何者錯誤？', '["若該車滅失不可歸責於乙，則免除給付該車之義務", "甲未取得購買之汽車，自無須支付價金", "若該車滅失可歸責於乙，甲得解除買賣契約", "若該車滅失可歸責於乙，甲得向乙請求損害賠償"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:47+00:00", "source_pdf_sha1": "1e9db8adb86c", "answer_pdf_sha1": "cdfbb1bd0c8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL)
